package br.gov.siscomex.portalunico.ttce.api;

import br.gov.siscomex.portalunico.ttce.model.ChamadaObterTratamentosTributariosImportacaoDTO;
import br.gov.siscomex.portalunico.ttce.model.RespostaObterTratamentosTributariosImportacaoDTO;
import io.swagger.annotations.Api;
import io.swagger.annotations.ApiOperation;
import io.swagger.annotations.ApiParam;
import io.swagger.annotations.ApiResponse;
import io.swagger.annotations.ApiResponses;

import javax.validation.Valid;
import javax.ws.rs.Consumes;
import javax.ws.rs.POST;
import javax.ws.rs.Path;
import javax.ws.rs.Produces;
import javax.ws.rs.core.Response;

/**
 * Tratamento Tributário
 *
 * <p><h4>Introdução</h4><p>O <strong>Tratamento Tributário do Comércio Exterior (TT ou TTCE)</strong> é o sistema responsável pelo cálculo de tributos incidentes na Importação, Exportação e Transporte de mercadorias. Com base nas informações de NCM, país de origem e valor aduaneiro, o sistema retorna o cálculo dos tributos incidentes em uma operação do Comércio Exterior.</p><hr/><style type=\"text/css\"> div.info tr, div.info th, div.info td { border: 1px solid lightgray; padding: 5px !important } </style><br/><h4>URLs de Acesso</h4><p>Para utilizar os serviços disponíveis nessa API deve-se seguir o seguinte padrão de URL:</p><p><em>https://{ambiente}/<strong>ttce</strong>{serviço}</em></p><p>Onde, em <strong>{ambiente}</strong> deve-se informar a <strong>URL de Acesso</strong> do ambiente desejado, dentre os ambientes disponíveis na tabela abaixo, e em <strong>{serviço}</strong> utilizar a URI do serviço desejado.</p><table style=\"width: 600px\"><thead  style=\"background: rgba(73,204,144,.1)\" ><tr><th style=\"border: 1px solid lightgray; padding: 5px;\" >Nome do Ambiente</th><th style=\"border: 1px solid lightgray; padding: 5px;\" >URL de Acesso</th></tr></thead><tbody><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >Ambiente de Validação das Empresas</td><td style=\"border: 1px solid lightgray; padding: 5px;\" >val.portalunico.siscomex.gov.br</td></tr><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >Ambiente de Produção</td><td style=\"border: 1px solid lightgray; padding: 5px;\" >portalunico.siscomex.gov.br</td></tr></tbody></table><br/><p><strong>Exemplo:</strong> Para o serviço \"que retorna os dados para auxiliar o importador a preencher a seção de Tratamento Tributário da DUIMP\" a URI é <strong>\"/api/ext/tratamentos-tributarios/importacao/\"</strong>.</p><p>Logo, abaixo temos um exemplo de URL completa, considerando o ambiente de Produção, consumindo este serviço:</p><p><em><a target=\"_blank\" href=\"https://portalunico.siscomex.gov.br/ttce/api/ext/tratamentos-tributarios/importacao/\">https://portalunico.siscomex.gov.br/ttce/api/ext/tratamentos-tributarios/importacao/</a></em></p><hr/><br/><h4>Dados de Apoio</h3><h5>&#8702; Lista de Regimes Tributários</h4><p>Use as informações abaixo para preencher o campo \"<strong>codigoRegime</strong>\".</p><table style=\"width: 600px;\"><thead  style=\"background: rgba(73,204,144,.1)\" ><tr><th style=\"border: 1px solid lightgray; padding: 5px;\" >Código</th><th style=\"border: 1px solid lightgray; padding: 5px;\" >Descrição</th></tr></thead><tbody><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >1</td><td style=\"border: 1px solid lightgray; padding: 5px;\" >RECOLHIMENTO INTEGRAL</td></tr><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >2</td><td style=\"border: 1px solid lightgray; padding: 5px;\" >IMUNIDADE</td></tr><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >3</td><td style=\"border: 1px solid lightgray; padding: 5px;\" >ISENÇÃO</td></tr><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >4</td><td style=\"border: 1px solid lightgray; padding: 5px;\" >REDUÇÃO</td></tr><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >5</td><td style=\"border: 1px solid lightgray; padding: 5px;\" >SUSPENSÃO</td></tr><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >6</td><td style=\"border: 1px solid lightgray; padding: 5px;\" >NÃO INCIDÊNCIA</td></tr><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >10</td><td style=\"border: 1px solid lightgray; padding: 5px;\" >SUSPENSÃO COM PAGAMENTO PROPORCIONAL DE TRIBUTO</td></tr></tbody></table><h5>&#8702; Lista de Tributos</h4><p>Use as informações abaixo para preencher o campo \"<strong>codigoTributo</strong>\".</p><table style=\"width: 600px;\"><thead  style=\"background: rgba(73,204,144,.1)\" ><tr><th style=\"border: 1px solid lightgray; padding: 5px;\" >Código</th><th style=\"border: 1px solid lightgray; padding: 5px;\" >Descrição</th></tr></thead><tbody><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >1</td><td style=\"border: 1px solid lightgray; padding: 5px;\" >IMPOSTO DE IMPORTAÇÃO</td></tr><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >2</td><td style=\"border: 1px solid lightgray; padding: 5px;\" >IPI</td></tr><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >3</td><td style=\"border: 1px solid lightgray; padding: 5px;\" >ANTIDUMPING</td></tr><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >4</td><td style=\"border: 1px solid lightgray; padding: 5px;\" >CIDE COMBUSTÍVEIS</td></tr><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >5</td><td style=\"border: 1px solid lightgray; padding: 5px;\" >MEDIDA COMPENSATÓRIA</td></tr><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >6</td><td style=\"border: 1px solid lightgray; padding: 5px;\" >PIS IMPORTAÇÃO</td></tr><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >7</td><td style=\"border: 1px solid lightgray; padding: 5px;\" >COFINS IMPORTAÇÃO</td></tr><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >8</td><td style=\"border: 1px solid lightgray; padding: 5px;\" >MULTAS REGULAMENTARES</td></tr><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >9</td><td style=\"border: 1px solid lightgray; padding: 5px;\" >SALVAGUARDA</td></tr><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >10</td><td style=\"border: 1px solid lightgray; padding: 5px;\" >TAXA SISCOMEX</td></tr><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >11</td><td style=\"border: 1px solid lightgray; padding: 5px;\" >IMPOSTO DE EXPORTAÇÃO</td></tr></tbody></table><br/><h5>&#8702; Lista de Fundamentos Legais</h5><p>Use uma das fontes de informação abaixo para preencher o campo \"<strong>codigoFundamentoLegal</strong>\".</p><ul><li> O TTCE fornece uma consulta pública de Fundamento Legal:<table style=\"width: 850px\"><thead  style=\"background: rgba(73,204,144,.1)\" ><tr><th style=\"border: 1px solid lightgray; padding: 5px;\" >Nome do Ambiente</th><th style=\"border: 1px solid lightgray; padding: 5px;\" >URL de Acesso</th></tr></thead><tbody><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >Ambiente de Validação das Empresas</td><td style=\"border: 1px solid lightgray; padding: 5px;\" ><a target=\"_blank\" href=\"https://val.portalunico.siscomex.gov.br/ttce/#/fundamento-legal/consultar?perfil=publico\">https://val.portalunico.siscomex.gov.br/ttce/#/fundamento-legal/consultar?perfil=publico</a></td></tr><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >Ambiente de Produção</td><td style=\"border: 1px solid lightgray; padding: 5px;\" ><a target=\"_blank\" href=\"https://portalunico.siscomex.gov.br/ttce/#/fundamento-legal/consultar?perfil=publico\">https://portalunico.siscomex.gov.br/ttce/#/fundamento-legal/consultar?perfil=publico</a></td></tr></tbody></table><br/><br/></li><li> O TABX fornece uma API de consulta para a tabela de Fundamento Legal (FUNDAMENTO_LEGAL_TT). Nesta consulta considerar os campos CODIGO e DESCRICAO:<table style=\"width: 850px\"><thead  style=\"background: rgba(73,204,144,.1)\" ><tr><th style=\"border: 1px solid lightgray; padding: 5px;\" >Nome do Ambiente</th><th style=\"border: 1px solid lightgray; padding: 5px;\" >URL de Acesso</th></tr></thead><tbody><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >Ambiente de Validação das Empresas</td><td style=\"border: 1px solid lightgray; padding: 5px;\" ><a href=\"https://val.portalunico.siscomex.gov.br/tabx/api/ext/tabela/FUNDAMENTO_LEGAL_TT\" target=\"_blank\">https://val.portalunico.siscomex.gov.br/tabx/api/ext/tabela/FUNDAMENTO_LEGAL_TT</a></td></tr><tr><td style=\"border: 1px solid lightgray; padding: 5px;\" >Ambiente de Produção</td><td style=\"border: 1px solid lightgray; padding: 5px;\" ><a href=\"https://portalunico.siscomex.gov.br/tabx/api/ext/tabela/FUNDAMENTO_LEGAL_TT\" target=\"_blank\">https://portalunico.siscomex.gov.br/tabx/api/ext/tabela/FUNDAMENTO_LEGAL_TT</a></td></tr></tbody></table></li></ul><br/><h5>&#8702; Lista de Países</h5><p>Use a fonte de informação abaixo para preencher o campo \"<strong>codigoPais</strong>\".</p><ul><li> O Sistema de Tabelas Aduaneiras fornece uma consulta de Países: <a href=\"https://www35.receita.fazenda.gov.br/tabaduaneiras-web/private/pages/telaInicial.jsf\" target=\"_blank\">Sistema de Tabelas Aduaneiras - País</a></li></ul><br/><hr/><br/><h4>Cenários de uso do serviço /api/ext/tratamentos-tributarios/importacao/</h4><ul><li><b>CENÁRIO 1:</b><br/><br/>O serviço pode ser acionado informando:<ul><li>NCM, país, data do fato gerador e tipo de operação.</li></ul><br/><br/>O serviço entrega:<ul><li>as informações dos atributos dos Fundamentos Legais dos tipos de uso normal e teto, caso existam;</li><li>a lista com as possíveis combinações de Tributo/Regime/Fundamento Legal do tipo de uso opcional.</li></ul><br/><br/>Exemplo dos parâmetros de entrada:<pre>{ &nbsp;&nbsp;&nbsp;&nbsp;\"ncm\": \"84149039\", &nbsp;&nbsp;&nbsp;&nbsp;\"codigoPais\": 158, &nbsp;&nbsp;&nbsp;&nbsp;\"dataFatoGerador\": \"2023-04-17\", &nbsp;&nbsp;&nbsp;&nbsp;\"tipoOperacao\": \"I\"  }</pre><hr/><br/><br/></li><li><b>CENÁRIO 2:</b><br/><br/>O serviço pode ser acionado informando:<ul><li>NCM, país, data do fato gerador e tipo de operação;</li><li>a lista de Fundamento Legal do tipo de uso opcional de interesse.</li></ul><br/><br/>O serviço entrega:<ul><li>as informações dos atributos dos Fundamentos Legais dos tipos de uso normal e teto, caso existam;</li><li>a lista dos Tributo/Regime/Fundamento Legal do tipo de uso opcional informada e as respectivas informações de atributos, caso existam.</li></ul><br/><br/>Exemplo dos parâmetros de entrada:<pre>{ &nbsp;&nbsp;&nbsp;&nbsp;\"ncm\": \"84149039\", &nbsp;&nbsp;&nbsp;&nbsp;\"codigoPais\": 158, &nbsp;&nbsp;&nbsp;&nbsp;\"dataFatoGerador\": \"2023-04-17\", &nbsp;&nbsp;&nbsp;&nbsp;\"tipoOperacao\": \"I\", &nbsp;&nbsp;&nbsp;&nbsp;\"fundamentosOpcionais\": [ &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;{ &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\"codigoTributo\": 1, &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\"codigoRegime\": 1, &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\"codigoFundamentoLegal\": 9 &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;} &nbsp;&nbsp;&nbsp;&nbsp;] }</pre><hr/><br/><br/></li><li><b>CENÁRIO 3:</b><br/><br/>O serviço pode ser acionado informando:<ul><li>NCM, país, data do fato gerador e tipo de operação;</li><li>a lista de Fundamento Legal do tipo de uso opcional de interesse.</li><ul><li>para cada item da lista, opcionalmente o código de nomenclatura alternativa.</li></ul></li></ul><br/><br/>O serviço entrega:<ul><li>as informações dos atributos dos Fundamentos Legais dos tipos de uso normal e teto, caso existam;</li><li>a lista dos Tributo/Regime/Fundamento Legal do tipo de uso opcional informada e as respectivas informações de atributos, caso existam.</li><li><b>Obs.:</b> nesse cenário o serviço retorna as mesmas informações do <b>CENÁRIO 2</b>, porém restrito à(s) nomenclatura(s) alternativa(s) informada(s).</li></ul><br/><br/>Exemplo dos parâmetros de entrada:<pre>{ &nbsp;&nbsp;&nbsp;&nbsp;\"ncm\": \"84149039\", &nbsp;&nbsp;&nbsp;&nbsp;\"codigoPais\": 158, &nbsp;&nbsp;&nbsp;&nbsp;\"dataFatoGerador\": \"2023-04-17\", &nbsp;&nbsp;&nbsp;&nbsp;\"tipoOperacao\": \"I\", &nbsp;&nbsp;&nbsp;&nbsp;\"fundamentosOpcionais\": [ &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;{ &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\"codigoTributo\": 1, &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\"codigoRegime\": 1, &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\"codigoFundamentoLegal\": 9, &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\"codigoNomenclaturaAlternativa\": \"06012000\"  &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;} &nbsp;&nbsp;&nbsp;&nbsp;] }</pre><br/><br/></li></ul><hr/>
 *
 */
@Path("/")
@Api(value = "/", description = "")
public interface ServiosParaOImportadorApi {

    /**
     * Serviço que retorna os dados para auxiliar o importador a preencher a lista de &#39;tributos&#39; no JSON do serviço para inclusão de itens na DUIMP. O retorno deste serviço contém os Fundamentos Legais de tipo de uso normal e teto que contenham atributos adicionais e todos os Fundamentos Legais de tipo de uso opcional (com ou sem atributos).
     *
     * Serviço que retorna os dados para auxiliar o importador a preencher a lista de &#39;tributos&#39; no JSON do serviço para inclusão de itens na DUIMP. O retorno deste serviço contém os Fundamentos Legais de tipo de uso normal e teto que contenham atributos adicionais e todos os Fundamentos Legais de tipo de uso opcional (com ou sem atributos).
     *
     */
    @POST
    @Path("/api/ext/tratamentos-tributarios/importacao/")
    @Consumes({"application/json"})
    @Produces({"application/json"})
    @ApiOperation(value = "Serviço que retorna os dados para auxiliar o importador a preencher a lista de 'tributos' no JSON do serviço para inclusão de itens na DUIMP. O retorno deste serviço contém os Fundamentos Legais de tipo de uso normal e teto que contenham atributos adicionais e todos os Fundamentos Legais de tipo de uso opcional (com ou sem atributos).", notes = "Serviço que retorna os dados para auxiliar o importador a preencher a lista de 'tributos' no JSON do serviço para inclusão de itens na DUIMP. O retorno deste serviço contém os Fundamentos Legais de tipo de uso normal e teto que contenham atributos adicionais e todos os Fundamentos Legais de tipo de uso opcional (com ou sem atributos).", tags = {"Serviços para o importador"})
    @ApiResponses(value = {
            @ApiResponse(code = 404, message = "Recurso não encontrado"),
            @ApiResponse(code = 500, message = "Erro interno no servidor"),
            @ApiResponse(code = 403, message = "Usuário não tem permissão de acesso ao recurso"),
            @ApiResponse(code = 400, message = "Requisição mal formatada"),
            @ApiResponse(code = 401, message = "Usuário não autenticado ou autenticação inválida"),
            @ApiResponse(code = 200, message = "Operação realizada com sucesso", response = RespostaObterTratamentosTributariosImportacaoDTO.class),
            @ApiResponse(code = 204, message = "Operação realizada com sucesso. Nenhum conteúdo retornado"),
            @ApiResponse(code = 422, message = "Erro(s) de validação da camada de negócio")})
    Response gerarJson(@ApiParam(value = "", required = true) @Valid ChamadaObterTratamentosTributariosImportacaoDTO body);
}

